def test_AC_05_phase_a_blocked_bulk_no_step7_marker():
    """
    Phase A: invoke write-bulk-commit-sentinel.py without an auth flag and
    assert (1) non-zero exit, (2) no sentinel file written, (3) no
    push-gate token created. Step 7 SKIP is documented in commit.md:176-181
    (BULK=true unconditionally skips Step 7), so no spec-continue marker
    can be emitted for this scenario.
    """
    script = REPO_ROOT / "scripts" / "write-bulk-commit-sentinel.py"
    assert script.exists()

    fake_sid = f"phase-a-{uuid.uuid4().hex[:8]}"
    with tempfile.TemporaryDirectory() as tmp:
        # Ensure no auth flag exists at the override path
        override_path = os.path.join(tmp, f"phase-a-auth-{fake_sid}.flag")
        assert not os.path.exists(override_path)

        env = os.environ.copy()
        env["CLAUDE_SESSION_ID"] = fake_sid
        env["CLAUDE_BULK_AUTH_FLAG_PATH_OVERRIDE"] = override_path

        # Run script with output-dir scoped to tmp so no /tmp pollution
        proc = subprocess.run(
            [sys.executable, str(script), "--output-dir", tmp],
            capture_output=True, text=True, env=env, timeout=10,
        )
        assert proc.returncode != 0, (
            f"Phase A: script must exit non-zero when auth flag absent\n"
            f"stdout: {proc.stdout}\nstderr: {proc.stderr}"
        )
        assert "BULK mode requires explicit user authorization" in proc.stderr

        # No sentinel file should have been created in tmp
        leftover = list(pathlib.Path(tmp).glob("claude-bulk-commit-sentinel-*.json"))
        assert leftover == [], f"Phase A: sentinel must not be written; found {leftover}"

    # commit.md Step 7 SKIP condition unchanged (BULK=true => skip)
    commit_md = (REPO_ROOT / "commands" / "commit.md").read_text(encoding="utf-8")
    assert "BULK=true" in commit_md
    assert "Step 7" in commit_md


